UPDATE application_case_initial_run
SET state = 'DONE',
    finished_at = NOW()
WHERE application_case_id = #{applicationCaseId}
  AND state = 'RUNNING'
  AND execution_token = #{executionToken}

UPDATE application_case_initial_run
SET state = 'FAILED',
    finished_at = NOW(),
    failure_reason = #{failureReason}
WHERE application_case_id = #{applicationCaseId}
  AND state = 'RUNNING'
  AND execution_token = #{executionToken}
